class MyMongoDBOperationsClass
{
    // Assuming $this->conn and $this->mongo_db are properties of the class

    /**
     * Deletes funnel page emails from the MongoDB collection.
     *
     * @param string $comm_button_id The communication button ID to match.
     * @param string $funnel_page_id The funnel page ID to match.
     *
     * @return void
     */
    public function deleteFunnelPageEmails($comm_button_id, $funnel_page_id)
    {
        // Initialize a new MongoDB BulkWrite object
        $bulk = new \MongoDB\Driver\BulkWrite;

        // Define the criteria for deletion
        $criteria = [
            'comm_button_id' => $comm_button_id,
            'funnel_page_id' => new \MongoDB\BSON\ObjectID($funnel_page_id)
        ];

        // Perform the delete operation
        $bulk->delete($criteria);

        // Execute the bulk write operation
        $this->conn->executeBulkWrite($this->mongo_db . '.funnel_page_emails', $bulk);
    }
}
```

